use std::collections::VecDeque;
use std::time::{SystemTime, UNIX_EPOCH};

struct DocumentHistory {
    documents: VecDeque<(String, u64)>,
}

impl DocumentHistory {
    fn new() -> Self {
        Self {
            documents: VecDeque::new(),
        }
    }

    fn add_document(&mut self, document_id: String, timestamp: u64) -> Result<(), String> {
        if self.documents.iter().any(|&(id, _)| id == document_id) {
            return Err(format!("Document with ID {} already exists.", document_id));
        }

        self.documents.push_back((document_id, timestamp));
        Ok(())
    }

    fn add_version(&mut self, document_id: String, timestamp: u64) -> Result<(), String> {
        if self.documents.iter().any(|&(id, _)| id == document_id) {
            return Err(format!("Document with ID {} already exists.", document_id));
        }

        let index = self.documents.iter().position(|&(id, _)| id == document_id).unwrap();
        self.documents.insert(index + 1, (document_id, timestamp));
        Ok(())
    }
}

fn main() {
    let mut history = DocumentHistory::new();

    // Add a new version of a document
    history.add_version("doc1".to_string(), SystemTime::now().duration_since(UNIX_EPOCH).unwrap().as_secs()).unwrap();

    // Add a new version of a document
    history.add_version("doc1".to_string(), SystemTime::now().duration_since(UNIX_EPOCH).unwrap().as_secs()).unwrap();

    // Attempt to add a version with duplicate timestamp
