package main

import (
    "errors"
    "fmt"
    "time"
)

type Reservation struct {
    Date time.Time
    Table int
}

type ReservationSystem struct {
    Reservations map[string][]Reservation
}

func NewReservationSystem() *ReservationSystem {
    return &ReservationSystem{
        Reservations: make(map[string][]Reservation),
    }
}

func (r *ReservationSystem) MakeReservation(customerName string, date time.Time, table int) error {
    key := customerName + "-" + date.Format(time.RFC3339)
    if _, ok := r.Reservations[key]; ok {
        return errors.New("double booking on the same date for the same table")
    }
    r.Reservations[key] = append(r.Reservations[key], Reservation{Date: date, Table: table})
    return nil
}

func (r *ReservationSystem) CancelReservation(customerName string, date time.Time, table int) error {
    key := customerName + "-" + date.Format(time.RFC3339)
    if _, ok := r.Reservations[key]; ok {
        for i, reservation := range r.Reservations[key] {
            if reservation.Date.Format(time.RFC3339) == date.Format(time.RFC3339) && reservation.Table == table {
                delete(r.Reservations[key], i)
                return nil
            }
        }
        return errors.New("no reservation found for the given customer and date")
    }
    return errors.New("customer not found")
}

func main() {
    reservationSystem := NewReservationSystem()
    reservationSystem.MakeReservation("John Doe", time.Now(), 1)
    reservationSystem.MakeReservation("Jane Doe", time.Now(), 2)
    reservationSystem.CancelReservation("John Doe", time.Now(), 1)
    fmt.Println(reservationSystem.Reservations)
}
