func createLogger() {
	// Create a map to store logs with timestamps as keys
	logs := make(map[string]struct{})

	// Function to insert a new log entry
	func(insertLog(timestamp time.Time, log string) {
		logs[timestamp.Format(time.RFC3339)] = struct{}{}
	} = func(timestamp time.Time, log string) {
		insertLog(timestamp, log)
	}

	// Function to delete old log entries
	func(deleteOldLogs(threshold time.Time) {
		for timestamp := range logs {
			if time.Time.Parse(time.RFC3339, timestamp) < threshold {
				delete(logs, timestamp)
			}
		}
	} = func(threshold time.Time) {
		deleteOldLogs(threshold)
	}

	// Example usage
	insertLog(time.Now(), "Log entry 1")
	insertLog(time.Now().Add(5 * time.Second), "Log entry 2")
	insertLog(time.Now().Add(10 * time.Second), "Log entry 3")

	fmt.Println(logs)

	deleteOldLogs(time.Now().Add(8 * time.Second))

	fmt.Println(logs)
}

func main() {
	createLogger()
