// Queue represents a First-In-First-Out (FIFO) queue.
type Queue struct {
    queue []int
}

// NewQueue returns a new instance of Queue.
func NewQueue() *Queue {
    return &Queue{queue: make([]int, 0)}
}

// PushBack adds a new user ID to the end of the queue.
func (q *Queue) PushBack(userID int) {
    q.queue = append(q.queue, userID)
}

// PushFront adds a new user ID to the front of the queue.
func (q *Queue) PushFront(userID int) {
    if len(q.queue) == 0 {
        q.queue = append(q.queue, userID)
    } else {
        q.queue = append([]int{userID}, q.queue...)
    }
}

// Dequeue removes and returns the user ID at the front of the queue.
func (q *Queue) Dequeue() (int, error) {
    if len(q.queue) == 0 {
        return 0, errors.New("queue is empty")
    }
    front := q.queue[0]
    q.queue = q.queue[1:]
    return front, nil
}

// PrintQueue prints the current state of the queue.
func (q *Queue) PrintQueue() {
    fmt.Println("Queue:", q.queue)
}

func main() {
    queue := NewQueue()

    queue.PushBack(1)
    queue.PushBack(2)
    queue.PushFront(0)
    queue.PrintQueue()

    front, _ := queue.Dequeue()
    fmt.Println("Dequeued:", front)

    queue.PushBack(3)
    queue.PrintQueue()
