import java.util.PriorityQueue;

public class EventScheduler {
    private PriorityQueue<Event> queue;

    public EventScheduler() {
        this.queue = new PriorityQueue<>();
    }

    public void addEvent(Event event) {
        try {
            queue.offer(event);
        } catch (Exception e) {
            System.out.println("An error occurred: " + e.getMessage());
        }
    }

    public Event getMostRecentEvent() {
        try {
            if (queue.isEmpty()) {
                return null;
            }
            return queue.poll();
        } catch (Exception e) {
            System.out.println("An error occurred: " + e.getMessage());
            return null;
        }
    }

    public static class Event implements Comparable<Event> {
        private String name;
        private int timestamp;

        public Event(String name, int timestamp) {
            this.name = name;
            this.timestamp = timestamp;
        }

        public String getName() {
            return name;
        }

        public int getTimestamp() {
            return timestamp;
        }

        @Override
        public int compareTo(Event other) {
            return Integer.compare(other.timestamp, this.timestamp);
        }
    }

    public static void main(String[] args) {
        EventScheduler scheduler = new EventScheduler();
        scheduler.addEvent(new Event("Event1", 10));
        scheduler.addEvent(new Event("Event2", 5));
        scheduler.addEvent(new Event("Event3", 15));

        while (true) {
            System.out.println("1. Get Most Recent Event");
            System.out.println("2. Add New Event");
            System.out.println("3. Exit");
            System.out.print("Choose an option: ");
            java.util.Scanner scanner = new java.util.Scanner(System.in);
            int option = scanner.nextInt();
            scanner.nextLine();

            switch (option) {
                case 1:
                    Event mostRecentEvent = scheduler.getMostRecentEvent();
                    if (mostRecentEvent == null) {
                        System.out.println("No events in the schedule.");
                    } else {
                        System.out.println("Name: " + mostRecentEvent.getName() + ", Timestamp: " + mostRecentEvent.getTimestamp());
                    }
                    break;
                case 2:
                    System.out.print("Enter event name: ");
                    String eventName = scanner.nextLine();
                    System.out.print("Enter event timestamp: ");
                    int eventTimestamp = scanner.nextInt();
                    scanner.nextLine();
                    scheduler.addEvent(new Event(eventName, eventTimestamp));
                    break;
                case 3:
                    System.exit(0);
                default:
                    System.out.println("Invalid option. Please choose again.");
            }
        }
    }
}
