// Cache represents a simple cache using a Go map.
type Cache struct {
	cache map[string]Page
}

// NewCache returns a new instance of the Cache struct.
func NewCache() *Cache {
	return &Cache{
		cache: make(map[string]Page),
	}
}

// Delete deletes a page from the cache by its key.
func (c *Cache) Delete(key string) {
	delete(c.cache, key)
}

// Get retrieves a page from the cache by its key. If the page is not found, it returns an error.
func (c *Cache) Get(key string) (Page, error) {
	if val, ok := c.cache[key]; ok {
		return val, nil
	}
	return Page{}, fmt.Errorf("page not found in cache")
}

// Set adds or updates a page in the cache.
func (c *Cache) Set(key string, page Page) {
	c.cache[key] = page
}

// Page represents a page with a title and content.
type Page struct {
	Title string
	Content string
}
